B.afZ=new A.c4("T\xe0n t\xedch n\xe0y kh\xf4ng ch\u1ec9 ch\xe1y b\u1edfi l\u1eeda, n\xf3 ch\xe1y b\u1edfi tham v\u1ecdng c\u1ee7a k\u1ebb m\u1ea1nh.","\u0110\u1ecbch tr\u01b0\u1edbc m\u1eaft kh\xf4ng ph\u1ea3i l\xfac n\xe0o c\u0169ng l\xe0 g\u1ed1c r\u1ec5. Ta ph\u1ea3i nh\xecn xa h\u01a1n.",null)
B.afV=new A.c4("Ng\u01b0\u01a1i t\u1edbi mu\u1ed9n r\u1ed3i, c\xf4ng l\xfd \u1edf \u0111\xe2y \u0111\xe3 b\u1ecb \u0111em ra mua b\xe1n.","Ta b\u1eaft \u0111\u1ea7u hi\u1ec3u: \u0111\xfang sai ch\u01b0a t\u1eebng \u0111\u01a1n gi\u1ea3n.",null)
B.ag9=new A.c4("Ta t\u1eebng tin tr\u1eafng \u0111en r\xf5 r\xe0ng. Lo\u1ea1n th\u1ebf \u0111\xe3 d\u1ea1y ta c\xe1i gi\xe1 c\u1ee7a s\u1ef1 ng\xe2y th\u01a1.","C\xf3 nh\u1eefng ng\u01b0\u1eddi c\u1ea7m \u0111ao v\xec b\u1ecb \xe9p, kh\xf4ng ph\u1ea3i v\xec mu\u1ed1n gi\u1ebft.",null)
B.agd=new A.c4("N\u1ebfu tr\u1eadt t\u1ef1 n\xe0y c\u1ea7n ng\u01b0\u1eddi v\xf4 t\u1ed9i l\xe0m gi\xe1, ta kh\xf4ng ph\u1ee5c t\xf9ng.","Ta ch\u1ecdn con \u0111\u01b0\u1eddng kh\xf3: s\u1eeda sai, kh\xf4ng ch\u1ec9 tr\u1ea3 th\xf9.",null)
B.ag4=new A.c4("Ng\u01b0\u01a1i mu\u1ed1n c\u1ee9u ng\u01b0\u1eddi? Tr\u01b0\u1edbc h\u1ebft h\u1ecdc c\xe1ch ch\u1ecbu \u0111\u1ef1ng s\u1ef1 th\u1eadt.","S\u1ef1 th\u1eadt \u0111au h\u01a1n ki\u1ebfm, nh\u01b0ng ch\u1ec9 n\xf3 m\u1edbi m\u1edf \u0111\u01b0\u1eddng.",null)
B.ag7=new A.c4("Ng\u01b0\u01a1i \u0111\xf2i c\xf4ng b\u1eb1ng cho thi\xean h\u1ea1, v\u1eady ai \u0111\xf2i c\xf4ng b\u1eb1ng cho k\u1ebb b\u1ecb hi sinh?","Ch\u1ee9ng c\u1ee9 cu\u1ed1i \u0111\xe3 r\xf5: li\xean minh th\u01b0\u01a1ng h\u1ed9i c\xf9ng hai tr\u01b0\u1edfng l\xe3o ph\u1ea3n m\xf4n \u0111\xe3 k\xedch n\u1ed5 kho Vi\xeam Tinh \u0111\u1ec3 chi\u1ebfm Linh M\u1ea1ch Vi\xeam T\xe2m, r\u1ed3i \u0111\u1ed5 t\u1ed9i cho ngo\u1ea1i \u0111\u1ecbch. Ta r\u1eddi t\xe0n t\xedch n\xe0y v\u1edbi \u0111\xe1p \xe1n nguy\xean nh\xe2n, kh\xf4ng c\xf2n l\xe0 k\u1ebb tr\u1ea3 th\xf9 m\xf9 qu\xe1ng.","N\u1ebfu ta ng\xe3 \u1edf t\xe0n t\xedch n\xe0y, ta c\u0169ng s\u1ebd th\xe0nh m\u1ed9t h\xf2n tro v\xf4 danh.")
B.a5Z=new A.bF(B.Bq,[B.afZ,B.afV,B.ag9,B.agd,B.ag4,B.ag7],t.mS)
B.agp=new A.c4("Bi\u1ec3n s\xe2u \u0111\xe8 n\u1eb7ng l\xean ng\u1ef1c, nh\u01b0 qu\xe1 kh\u1ee9 \u0111\xe8 n\u1eb7ng l\xean tim.","\xc1p l\u1ef1c bi\u1ec3n s\xe2u kh\xf4ng l\xe0m ta s\u1ee3 b\u1eb1ng vi\u1ec7c b\u1ecf m\u1eb7c ng\u01b0\u1eddi kh\xe1c ch\xecm xu\u1ed1ng.",null)
B.agn=new A.c4("\u1ede \u0111\xe2y, ch\u1ec9 k\u1ebb d\xe1m th\u1edf trong tuy\u1ec7t v\u1ecdng m\u1edbi \u0111i ti\u1ebfp \u0111\u01b0\u1ee3c.","Ta \u0111\xe3 quen \u0111au, nh\u01b0ng ch\u01b0a t\u1eebng quen nh\xecn d\xe2n th\u01b0\u1eddng ch\u1ecbu \u0111au.",null)
B.agc=new A.c4("Ng\u01b0\u01a1i c\u1ee9u \u0111\u01b0\u1ee3c m\xecnh, ch\u01b0a ch\u1eafc c\u1ee9u \u0111\u01b0\u1ee3c thi\xean h\u1ea1.","N\u1ebfu s\u1ee9c m\u1ea1nh ch\u1ec9 c\u1ee9u m\u1ed9t m\xecnh ta, th\xec s\u1ee9c m\u1ea1nh \u0111\xf3 v\xf4 ngh\u0129a.",null)
B.ag2=new A.c4("S\u1ef1 th\u1eadt v\u1ec1 s\u01b0 ph\u1ee5 ng\u01b0\u01a1i \u0111ang \u1edf ph\xeda tr\u01b0\u1edbc. Ng\u01b0\u01a1i c\xf3 d\xe1m \u0111\u1ed1i di\u1ec7n kh\xf4ng?","Ng\u01b0\u1eddi \u0111i tr\u01b0\u1edbc \u0111\xe3 ng\xe3 \u0111\u1ec3 ta c\xf2n l\u1ef1a ch\u1ecdn. Ta kh\xf4ng \u0111\u01b0\u1ee3c ph\xe9p s\u1ed1ng h\xe8n.",null)
B.agj=new A.c4("M\u1ed9t quy\u1ebft \u0111\u1ecbnh c\u1ee7a ng\u01b0\u01a1i, tri\u1ec7u ng\u01b0\u1eddi s\u1ebd ph\u1ea3i tr\u1ea3 gi\xe1.","Tr\u01b0\u1edfng th\xe0nh l\xe0 d\xe1m tr\u1ea3 gi\xe1 cho \u0111i\u1ec1u m\xecnh tin, kh\xf4ng ph\u1ea3i n\xe9 tr\xe1nh c\xe1i gi\xe1 \u1ea5y.",null)
B.ag5=new A.c4("Ch\u1ecdn \u0111i, t\u1ea3n tu: an to\xe0n cho s\u1ed1 \xedt, hay \u0111au \u0111\u1edbn \u0111\u1ec3 m\u1edf m\u1ed9t t\u01b0\u01a1ng lai m\u1edbi cho t\u1ea5t c\u1ea3?","Phong \u1ea5n Enkavia \u0111\xe3 m\u1edf, to\xe0n b\u1ed9 k\xfd l\u1ee5c ph\u1ea3n b\u1ed9i \u0111\u01b0\u1ee3c c\xf4ng b\u1ed1 tr\u01b0\u1edbc c\xe1c t\xf4ng m\xf4n. T\u1eeb \u0111\xe2y v\xf2ng l\u1eb7p ch\xe9m gi\u1ebft b\u1ecb b\u1ebb g\xe3y: k\u1ebb ch\u1ee7 m\u01b0u b\u1ecb truy n\xe3, d\xe2n th\u01b0\u1eddng \u0111\u01b0\u1ee3c l\u1eadp \u01b0\u1edbc b\u1ea3o h\u1ed9. Ta kh\xf4ng th\u1eafng ch\u1ec9 cho ri\xeang m\xecnh, m\xe0 \u0111\u1ec3 kh\xe9p l\u1ea1i m\u1ed9t ch\u01b0\u01a1ng \u0111\u1eabm m\xe1u.","N\u1ebfu ta g\u1ee5c xu\u1ed1ng, th\u1ebf gi\u1edbi n\xe0y s\u1ebd l\u1ea1i r\u01a1i v\xe0o tay k\u1ebb ch\u1ec9 bi\u1ebft ch\u1ecdn ph\u1ea7n d\u1ec5.")
